// Authorize the claim: validate the shared secret token and the lead id from the
// email link. The Claim now button is built in the triage workflow with the same
// claimSecret, so a link with a wrong/absent token is rejected before any API call.
const cfg = $('Claim Config').first().json;
const q = ($('Claim Webhook').first().json.query) || {};
const leadId = String(q.lead_id || '').trim();
const token = String(q.t || '');
const page = (title, body, color) => `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${title}</title></head><body style="font:16px/1.5 -apple-system,system-ui,Segoe UI,Arial,sans-serif;background:#f6f8fa;margin:0;padding:48px 20px;color:#1f2328"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:12px;padding:28px 24px;box-shadow:0 1px 4px rgba(0,0,0,.08);border-top:5px solid ${color}"><h1 style="font-size:20px;margin:0 0 8px">${title}</h1><div style="color:#57606a">${body}</div></div></body></html>`;
const secretSet = cfg.claimSecret && !/PUT_|YOUR_/.test(String(cfg.claimSecret));
if (!secretSet || token !== String(cfg.claimSecret)) {
  return [{ json: { ok: false, leadId, html: page('Not authorized', 'This claim link is missing or carries an invalid token.', '#cf222e') } }];
}
if (!/^\d+$/.test(leadId)) {
  return [{ json: { ok: false, leadId, html: page('Bad link', 'No valid lead id was provided.', '#cf222e') } }];
}
return [{ json: { ok: true, leadId, assignee: cfg.claimAssignee } }];

// Build the confirmation page from the assignment response (the Assign node runs
// with neverError, so a Lofty rejection lands here as a body instead of failing).
const v = $('Verify & Authorize').first().json;
const leadId = v.leadId;
const resp = $json;
const page = (title, body, color) => `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>${title}</title></head><body style="font:16px/1.5 -apple-system,system-ui,Segoe UI,Arial,sans-serif;background:#f6f8fa;margin:0;padding:48px 20px;color:#1f2328"><div style="max-width:460px;margin:0 auto;background:#ffffff;border-radius:12px;padding:28px 24px;box-shadow:0 1px 4px rgba(0,0,0,.08);border-top:5px solid ${color}"><h1 style="font-size:20px;margin:0 0 8px">${title}</h1><div style="color:#57606a">${body}</div></div></body></html>`;
// Success = Lofty echoed a leadId (LeadIdResponse) and returned no error code/message.
const ok = !!resp && !resp.code && !resp.message && (resp.leadId || Array.isArray(resp));
const html = ok
  ? page('Claimed \u2713', 'Lead ' + leadId + ' is assigned to you. Open Lofty to start working it.', '#1a7f37')
  : page('Claim failed', 'Lofty did not accept the assignment (' + (resp.code || resp.message || 'unknown error') + '). The lead was not claimed \u2014 try again, or claim it in Lofty.', '#9a6700');
return [{ json: { html, ok, leadId, lofty: resp } }];
